import {
  Activity, BarChart3, GitCompare, Star, ShieldCheck, Layers, Timer, LineChart, Search,
} from "lucide-react";
import { motion } from "framer-motion";
import { Reveal } from "./motion";

const features = [
  { icon: Activity, title: "Median prices", body: "Updated every 5 minutes from the Castia auction house." },
  { icon: ShieldCheck, title: "Confidence ratings", body: "Know which prices to trust — High, Good, Fair, Low or Unreliable." },
  { icon: LineChart, title: "Trend indicators", body: "Rising, falling or stable arrows on every item, every refresh." },
  { icon: BarChart3, title: "IQR ranges", body: "Middle-50% spread so you can spot volatile markets at a glance." },
  { icon: GitCompare, title: "Compare items", body: "Side-by-side comparison of medians, confidence, and trends." },
  { icon: Star, title: "Favorites", body: "Pin items you care about and keep them within one click." },
  { icon: Layers, title: "12 categories", body: "Set gear, runestones, spawners, relics, vanilla, music discs — all of it." },
  { icon: Search, title: "Smart filters", body: "Filter by confidence, tier and category. Sort by anything." },
  { icon: Timer, title: "Data saver mode", body: "Hide images on slow connections without losing data." },
];

export default function Features() {
  return (
    <section
      id="features"
      data-testid="features-section"
      className="relative py-24 md:py-32"
    >
      <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">
              / Features
            </div>
            <h2 className="font-heading text-4xl sm:text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95]">
              Built for traders<br />who hate guessing.
            </h2>
          </Reveal>
          <Reveal delay={0.15} className="max-w-md text-zinc-400 text-base leading-relaxed">
            Every metric you need to price an item correctly — and nothing
            you don't. No mods. No accounts. Just data.
          </Reveal>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-px bg-zinc-800/30 rounded-2xl overflow-hidden border border-white/5">
          {features.map((f, i) => {
            const Icon = f.icon;
            // 9 features → 3×3 on lg, but sm is 2 cols and the last row only
            // has one card. Span the final card so it fills the row instead
            // of leaving dead space on tablet widths.
            const isLastOdd = i === features.length - 1 && features.length % 2 === 1;
            return (
              <motion.div
                key={f.title}
                data-testid={`feature-card-${i}`}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-80px" }}
                transition={{ delay: (i % 3) * 0.08 + Math.floor(i / 3) * 0.05, duration: 0.7, ease: [0.16, 1, 0.3, 1] }}
                whileHover={{ y: -4 }}
                className={`group bg-bg-base hover:bg-bg-surface transition-colors p-8 md:p-10 relative ${isLastOdd ? "sm:col-span-2 lg:col-span-1" : ""}`}
              >
                <div className="relative w-12 h-12 mb-6 grid place-items-center">
                  <div className="absolute inset-0 bg-emerald-500/10 blur-xl rounded-full group-hover:bg-emerald-500/30 transition-all"></div>
                  <Icon className="relative w-6 h-6 text-emerald-400" strokeWidth={1.5} />
                </div>
                <h3 className="font-heading text-xl font-bold text-white mb-3 tracking-tight">
                  {f.title}
                </h3>
                <p className="text-zinc-400 leading-relaxed">{f.body}</p>
              </motion.div>
            );
          })}
        </div>
      </div>
    </section>
  );
}
