import { categoryBreakdown as mockCats, priceDistribution as mockDist } from "@/lib/mockData";
import { BarChart, Bar, XAxis, YAxis, ResponsiveContainer, Cell } from "recharts";
import { motion } from "framer-motion";
import { Reveal } from "./motion";
import { useMarket } from "@/lib/MarketContext";
import { CountUp } from "./CountUp";

export default function StatsBento() {
  const { market, loading } = useMarket();
  const cats = market?.categoryBreakdown?.length ? market.categoryBreakdown : mockCats;
  const dist = market?.priceDistribution?.length ? market.priceDistribution : mockDist;
  const totalTracked = market ? market.stats.totalItems : 847;
  const highConfidence = market ? market.stats.highConfidence : 186;

  return (
    <section data-testid="stats-bento-section" className="relative py-24 md:py-32 overflow-hidden">
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[400px] bg-amber-500/5 blur-[120px] rounded-full pointer-events-none"></div>
      <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16 relative">
        <Reveal className="max-w-3xl mb-16">
          <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-amber-400 mb-4">/ Market Composition</div>
          <h2 className="font-heading text-4xl sm:text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95]">
            {market ? market.stats.categories : 12} categories.<br />
            <span className="tabular">{totalTracked.toLocaleString()}+</span> items.
          </h2>
        </Reveal>

        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 grid-flow-row-dense">
          <Reveal className="md:col-span-7 md:row-span-2">
            <div data-testid="categories-breakdown-card" className="bg-white/[0.02] border border-white/10 rounded-2xl p-8 md:p-10 hover:border-white/25 transition-smooth h-full">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">Top categories</div>
              <h3 className="font-heading text-2xl font-bold mb-8">By share of listings</h3>
              <div className="space-y-5">
                {cats.map((c, i) => (
                  <div key={c.name} data-testid={`category-bar-${c.name.toLowerCase().replace(/\s+/g, "-")}`}>
                    <div className="flex items-center justify-between mb-2">
                      <div className="flex items-center gap-3">
                        <span className="w-2.5 h-2.5 rounded-sm" style={{ backgroundColor: c.color }}></span>
                        <span className="font-medium text-white">{c.name}</span>
                      </div>
                      <div className="flex items-center gap-4 font-mono text-xs text-zinc-400">
                        <span className="tabular">{c.value} items</span>
                        <span className="text-white w-10 text-right tabular">{c.pct}%</span>
                      </div>
                    </div>
                    <div className="h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                      <motion.div
                        className="h-full rounded-full origin-left"
                        initial={{ scaleX: 0 }}
                        whileInView={{ scaleX: 1 }}
                        viewport={{ once: true }}
                        transition={{ duration: 1.2, ease: [0.16, 1, 0.3, 1], delay: i * 0.08 }}
                        style={{
                          width: `${c.pct}%`,
                          backgroundColor: c.color,
                        }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </Reveal>

          <Reveal delay={0.1} className="md:col-span-5">
            <div data-testid="price-distribution-card" className="bg-white/[0.02] border border-white/10 rounded-2xl p-8 md:p-10 hover:border-white/25 transition-smooth flex flex-col h-full">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">Price tiers</div>
              <h3 className="font-heading text-2xl font-bold mb-8">Item distribution by price</h3>
              <div className="flex-1 min-h-[200px]">
                <ResponsiveContainer width="100%" height={220}>
                  <BarChart data={dist} margin={{ top: 0, right: 0, left: 0, bottom: 0 }}>
                    <XAxis dataKey="range" stroke="#71717A" fontSize={10} tickLine={false} axisLine={false} style={{ fontFamily: "Geist Mono" }} />
                    <YAxis stroke="#71717A" fontSize={10} tickLine={false} axisLine={false} style={{ fontFamily: "Geist Mono" }} />
                    <Bar dataKey="count" radius={[6, 6, 0, 0]} animationDuration={1200}>
                      {dist.map((_, i) => (<Cell key={i} fill={["#10B981", "#34D399", "#FBBF24", "#F59E0B"][i]} />))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
              <div className="grid grid-cols-4 gap-2 mt-4 pt-4 border-t border-white/10">
                {dist.map((p) => (
                  <div key={p.range} className="text-center">
                    <div className="font-mono text-[9px] uppercase tracking-wider text-zinc-500">{p.range}</div>
                    <div className="font-heading font-bold text-white tabular">{p.count}</div>
                  </div>
                ))}
              </div>
            </div>
          </Reveal>

          <Reveal delay={0.05} className="md:col-span-5">
            <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-2xl p-8 md:p-10 relative overflow-hidden hover:border-emerald-500/50 transition-smooth h-full">
              <div className="absolute inset-0 bg-grid opacity-30"></div>
              <div className="relative">
                <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-emerald-300 mb-2">Total tracked</div>
                <div data-testid="kpi-total" className="font-heading text-7xl font-black tracking-tighter text-white tabular">
                  {loading.market ? "—" : <CountUp value={totalTracked} format={(v) => v.toLocaleString()} duration={1.4} />}
                </div>
                <div className="font-mono text-xs text-emerald-300/80 mt-2">unique items live</div>
              </div>
            </div>
          </Reveal>

          <Reveal delay={0.1} className="md:col-span-6">
            <div className="bg-white/[0.02] border border-white/10 rounded-2xl p-8 md:p-10 hover:border-white/25 transition-smooth h-full">
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">High confidence prices</div>
              <div data-testid="kpi-high-conf" className="font-heading text-7xl font-black tracking-tighter text-white tabular">
                {loading.market ? "—" : <CountUp value={highConfidence} format={(v) => v.toLocaleString()} duration={1.4} />}
              </div>
              <div className="font-mono text-xs text-zinc-500 mt-2">stable, well-sampled markets</div>
            </div>
          </Reveal>

          <Reveal delay={0.15} className="md:col-span-6">
            <div className="bg-white/[0.02] border border-white/10 rounded-2xl p-8 md:p-10 hover:border-white/25 transition-smooth relative overflow-hidden h-full">
              <div className="absolute top-4 right-4">
                <span className="relative flex h-2 w-2">
                  <span className="absolute inline-flex h-full w-full rounded-full bg-amber-400 opacity-75 animate-ping"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-amber-500"></span>
                </span>
              </div>
              <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">Refresh cadence</div>
              <div className="font-heading text-7xl font-black tracking-tighter text-amber-400 tabular">5m</div>
              <div className="font-mono text-xs text-zinc-500 mt-2">automatic, no setup</div>
            </div>
          </Reveal>
        </div>
      </div>
    </section>
  );
}
