import { TrendingUp, TrendingDown, Minus, ArrowUpRight, Loader2 } from "lucide-react";
import { Link, useSearchParams } from "react-router-dom";
import { trendingItems as mockTrending, sparklineData } from "@/lib/mockData";
import { LineChart, Line, ResponsiveContainer } from "recharts";
import { Reveal } from "./motion";
import { useMarket } from "@/lib/MarketContext";
import { openItem } from "./DetailDrawer";
import { PriceMorph } from "./CountUp";
import ItemName from "./ItemName";

const TrendIcon = ({ trend }) => {
  if (trend === "rising") return <TrendingUp className="w-3.5 h-3.5 text-emerald-400" />;
  if (trend === "falling") return <TrendingDown className="w-3.5 h-3.5 text-red-400" />;
  return <Minus className="w-3.5 h-3.5 text-zinc-500" />;
};

const ConfDot = ({ conf }) => {
  const map = { high: "bg-emerald-400", good: "bg-lime-400", fair: "bg-amber-400", low: "bg-orange-400", unreliable: "bg-zinc-600" };
  return <span className={`inline-block w-1.5 h-1.5 rounded-full ${map[conf] || "bg-zinc-600"}`}></span>;
};

export default function MarketPreview() {
  const { market, loading, error } = useMarket();
  const isLive = !loading.market && !error.market && !!market;
  const featured = market?.featured;
  const rows = market?.topMovers || mockTrending;
  const [searchParams, setSearchParams] = useSearchParams();

  const sideStats = [
    { label: "Priced items", value: market ? String(market.stats.pricedItems) : "742", sub: market ? `of ${market.stats.totalItems} tracked` : "of 847 tracked", to: "/listings" },
    { label: "Avg median", value: market ? market.stats.avgMedian : "542.9K", sub: "across all items", to: "/listings" },
    { label: "Rising items", value: market ? String(market.stats.risingItems) : "138", sub: "in the last 24h", accent: "emerald", to: "/listings?r=rising" },
  ];

  return (
    <section id="market" data-testid="market-preview-section" className="relative py-24 md:py-32 overflow-hidden">
      <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">
              / Live Market Snapshot {isLive && <span className="text-zinc-500">· {market.stats.lastUpdated}</span>}
            </div>
            <h2 className="font-heading text-4xl sm:text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95]">
              See the market<br />
              <span className="text-emerald-400">move</span> in real time.
            </h2>
          </Reveal>
          <Reveal delay={0.15} className="max-w-md text-zinc-400 text-base leading-relaxed">
            Median prices, IQR spread, sample volume and trend velocity for every tracked item — distilled into a single, glanceable view.
          </Reveal>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-12 gap-6 mb-6">
          <Reveal delay={0.05} className="md:col-span-8">
            <button
              data-testid="featured-item-card"
              onClick={() => featured?.key && openItem(searchParams, setSearchParams, featured.key)}
              className="relative w-full text-left overflow-hidden bg-white/[0.02] border border-white/10 rounded-2xl p-8 md:p-12 group hover:border-emerald-500/40 transition-smooth h-full"
            >
              <div className="absolute -top-20 -right-20 w-72 h-72 bg-emerald-500/20 blur-[100px] rounded-full"></div>
              <div className="absolute inset-0 bg-grid opacity-30 [mask-image:radial-gradient(ellipse_at_top_right,_black_20%,_transparent_70%)]"></div>

              <div className="relative flex flex-col h-full">
                <div className="flex items-center gap-3 mb-6 flex-wrap">
                  <span className="font-mono text-[10px] uppercase tracking-[0.25em] text-emerald-400 px-2 py-1 border border-emerald-500/30 rounded-sm">
                    Highest median · Featured
                  </span>
                  <span data-testid="featured-category" className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500">
                    {featured?.category || "Set Gear"}
                  </span>
                  {loading.market && (
                    <span className="inline-flex items-center gap-1.5 font-mono text-[10px] uppercase tracking-[0.25em] text-amber-300">
                      <Loader2 className="w-3 h-3 animate-spin" /> Loading
                    </span>
                  )}
                  <span className="ml-auto font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 inline-flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    Open detail <ArrowUpRight className="w-3 h-3" />
                  </span>
                </div>

                <div className="flex-1">
                  <div data-testid="featured-name" className="font-mono text-xs text-zinc-500 mb-3">
                    {featured?.name
                      ? <ItemName name={featured.name} tier={featured.tier} modifiers={featured.modifiers} />
                      : <span>Prismatic Pickaxe</span>}
                  </div>
                  <div data-testid="featured-price" className="font-heading text-6xl sm:text-7xl lg:text-8xl font-black tracking-tighter text-white leading-none">
                    {loading.market ? (
                      <span className="inline-block h-20 w-72 bg-white/5 rounded animate-pulse" />
                    ) : (
                      <PriceMorph value={featured?.medianRaw || 75_000_000} />
                    )}
                  </div>
                  <div className="mt-4 flex flex-wrap items-center gap-4 font-mono text-sm text-zinc-400">
                    <span className={`inline-flex items-center gap-1.5 ${
                      featured?.trend === "up" ? "text-emerald-400" : featured?.trend === "down" ? "text-red-400" : "text-zinc-400"
                    }`}>
                      {featured?.trend === "up" ? <TrendingUp className="w-4 h-4" /> :
                       featured?.trend === "down" ? <TrendingDown className="w-4 h-4" /> :
                       <Minus className="w-4 h-4" />}
                      {featured?.trend === "up" ? "Rising" : featured?.trend === "down" ? "Falling" : "Stable"}
                    </span>
                    <span className="tabular">IQR {featured?.iqrLow || "64.2M"} — {featured?.iqrHigh || "86.1M"}</span>
                    <span className="inline-flex items-center gap-1.5"><ConfDot conf={featured?.confidence || "high"} />{featured?.confidence || "high"} confidence</span>
                    <span className="tabular">{featured?.samples || 64} samples</span>
                  </div>
                </div>

                <div className="relative h-24 mt-8 -mx-2">
                  <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={sparklineData}>
                      <Line type="monotone" dataKey="v" stroke="#10B981" strokeWidth={2.5} dot={false} isAnimationActive={true} animationDuration={1400} />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </button>
          </Reveal>

          <div className="md:col-span-4 grid grid-cols-2 md:grid-cols-1 gap-6">
            {sideStats.map((s, i) => (
              <Reveal key={s.label} delay={0.1 + i * 0.08}>
                <Link to={s.to} className="block h-full">
                  <div data-testid={`side-stat-${s.label.toLowerCase().replace(/\s+/g, "-")}`} className="bg-white/[0.02] border border-white/10 rounded-2xl p-6 hover:border-emerald-500/40 transition-smooth h-full">
                    <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-3">{s.label}</div>
                    <div className={`font-heading text-3xl lg:text-4xl font-black tracking-tighter tabular ${s.accent === "emerald" ? "text-emerald-400" : "text-white"}`}>
                      {loading.market ? <span className="inline-block h-8 w-24 bg-white/5 rounded animate-pulse" /> : s.value}
                    </div>
                    <div className="font-mono text-xs text-zinc-500 mt-2">{s.sub}</div>
                  </div>
                </Link>
              </Reveal>
            ))}
          </div>
        </div>

        <Reveal delay={0.2}>
          <div data-testid="trending-table" className="bg-bg-deeper border border-white/10 rounded-2xl overflow-hidden">
            <div className="flex items-center justify-between px-6 py-5 border-b border-white/10">
              <div className="flex items-center gap-3">
                <span className="relative flex h-2 w-2">
                  {isLive && <span className="absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75 animate-ping"></span>}
                  <span className={`relative inline-flex rounded-full h-2 w-2 ${isLive ? "bg-emerald-500" : "bg-amber-500"}`}></span>
                </span>
                <h3 className="font-heading font-bold tracking-tight">Top Items</h3>
                <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">
                  {isLive ? `live · 8 of ${market.stats.totalItems}` : loading.market ? "loading…" : "8 items"}
                </span>
              </div>
              <Link to="/listings" data-testid="view-all-items-link" className="font-mono text-[11px] uppercase tracking-[0.2em] text-zinc-400 hover:text-emerald-400 inline-flex items-center gap-1 transition-colors">
                View all <ArrowUpRight className="w-3 h-3" />
              </Link>
            </div>

            {/* Wrapper is overflow-x-auto on mobile (the 6-column table
                can't fit the page width), and overflow-x-visible on
                md+ so desktop doesn't get a horizontal scrollbar. */}
            <div className="overflow-x-auto md:overflow-x-visible custom-scrollbar accelerated">
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-left font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 border-b border-white/5">
                    <th className="px-4 sm:px-6 py-3 font-medium">Item</th>
                    <th className="px-4 sm:px-6 py-3 font-medium hidden sm:table-cell">Category</th>
                    <th className="px-4 sm:px-6 py-3 font-medium text-right">Median</th>
                    <th className="px-4 sm:px-6 py-3 font-medium hidden md:table-cell">Trend</th>
                    <th className="px-4 sm:px-6 py-3 font-medium hidden md:table-cell">Conf.</th>
                    <th className="px-4 sm:px-6 py-3 font-medium text-right hidden lg:table-cell">Samples</th>
                  </tr>
                </thead>
                <tbody>
                  {loading.market
                    ? Array.from({ length: 6 }).map((_, i) => (
                        <tr key={i} className="border-b border-white/5">
                          <td className="px-4 sm:px-6 py-4" colSpan={6}>
                            <div className="h-4 bg-white/5 rounded animate-pulse" />
                          </td>
                        </tr>
                      ))
                    : rows.map((item, i) => (
                        <tr
                          key={`${item.key || item.name}-${i}`}
                          data-testid={`trending-row-${i}`}
                          onClick={() => item.key && openItem(searchParams, setSearchParams, item.key)}
                          // No framer-motion entry animation here: when
                          // the entry animation's y-offset was still in
                          // flight, hovering the row would cause a
                          // visible "glitch" as the row snapped from
                          // its animated position to the hover state.
                          // The table is small enough that the entry
                          // animation was visual noise anyway, so a
                          // plain static row reads cleaner.
                          className="border-b border-white/5 last:border-0 hover:bg-white/[0.02] transition-colors cursor-pointer"
                        >
                          <td className="px-4 sm:px-6 py-4"><div className="font-medium text-white"><ItemName name={item.name} tier={item.tier} modifiers={item.modifiers} /></div></td>
                          <td className="px-4 sm:px-6 py-4 font-mono text-xs text-zinc-400 hidden sm:table-cell">{item.category}</td>
                          <td className="px-4 sm:px-6 py-4 font-mono text-right text-white tabular">{item.median}</td>
                          <td className="px-4 sm:px-6 py-4 hidden md:table-cell"><TrendIcon trend={item.trend} /></td>
                          <td className="px-4 sm:px-6 py-4 hidden md:table-cell">
                            <span className="inline-flex items-center gap-1.5 font-mono text-xs text-zinc-400">
                              <ConfDot conf={item.conf} /> {item.conf}
                            </span>
                          </td>
                          <td className="px-4 sm:px-6 py-4 font-mono text-right text-zinc-400 hidden lg:table-cell tabular">{item.samples}</td>
                        </tr>
                      ))}
                </tbody>
              </table>
            </div>
          </div>
        </Reveal>
      </div>
    </section>
  );
}
