function HeroStat({ label, value, loading }) {
  return (
    <div className="bg-bg-base/80 px-6 py-6">
      <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">{label}</div>
      <div className="font-heading font-extrabold text-2xl sm:text-3xl text-white">
        {loading ? (
          <span className="inline-block h-7 w-20 bg-white/5 rounded animate-pulse" />
        ) : (
          <CountUp value={value} format={(v) => v.toLocaleString()} duration={1.2} />
        )}
      </div>
    </div>
  );
}
